#include <stdio.h>
#include <string.h>

#define MAXN 100000

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        scanf("%d", &n);
        static char a[MAXN + 5];
        static char b[MAXN + 5];
        scanf("%s %s", a, b);
        int cntA[26] = {0}, cntB[26] = {0};
        for (int i = 0; i < n; ++i) {
            cntA[a[i] - 'a']++;
            cntB[b[i] - 'a']++;
        }
        int ok = 1;
        for (int i = 0; i < 26; ++i) {
            if (cntA[i] != cntB[i]) { ok = 0; break; }
        }
        printf(ok ? "Yes\n" : "No\n");
    }
    return 0;
}

