const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let results = [];
for (let t = 0; t < T; ++t) {
  const n = Number(input[idx++]);
  const a = input[idx++];
  const b = input[idx++];
  const cnt = new Array(26).fill(0);
  for (let i = 0; i < n; ++i) cnt[a.charCodeAt(i) - 97]++;
  for (let i = 0; i < n; ++i) cnt[b.charCodeAt(i) - 97]--;
  let ok = true;
  for (let i = 0; i < 26; ++i) {
    if (cnt[i] !== 0) { ok = false; break; }
  }
  results.push(ok ? 'Yes' : 'No');
}
console.log(results.join('\n'));

